final:
module counter_up_down(
	input wire clk,
	input wire clear,
	input wire en,
	input wire up_down,
	output reg [7:0] obf_Q
);always @(posedge clk) begin
	if (clear)
		obf_Q <= 8'b00000000;
	else if (en) begin
		if (up_down)
			obf_Q <= obf_Q + 1;
		else
			obf_Q <= obf_Q - 1;
	end
end
endmodule
